/*********************************************************
 * Verify if exist at least one row configured for styles 
 * 
 * by Cinthia Romero
 ********************************************************/
var cssGrid = this.EGP_CSS_CONFIGURATION;
var showCSSMessage = "YES";
if (Object.keys(cssGrid).length > 0) {
    showCSSMessage = "NO";
}
return showCSSMessage;

/*********************************************************
 * Verify if exist at least one row configured for columns 
 * 
 * by Cinthia Romero
 ********************************************************/
var columnsGrid = this.EGP_COLUMNS_CONFIGURATION;
var showColumnsMessage = "YES";
if (Object.keys(columnsGrid).length > 0) {
    showColumnsMessage = "NO";
}
return showColumnsMessage;

/*********************************************
 * Check if format date field should be shown
 * 
 * by Cinthia Romero
 ********************************************/
var tableVariables = this.ECC_TABLE_VARIABLES;
var showDateFormat = "NO";
for(var i = 0; i < tableVariables.length; i++) {
    if (tableVariables[i]["ECC_ARRAY_VARIABLE_TYPE"] == "Date" || this.ECC_VARIABLE_TYPE == "Date") {
        showDateFormat = "YES";
    }
}
return showDateFormat;

/*************************************************
 * Check if currency format field shoudl be shown
 * 
 * by Cinthia Romero
 ************************************************/
var tableVariables = this.ECC_TABLE_VARIABLES;
var showCurrencyFormat = "NO";
if (this.ECC_VALUE_TYPE == "Variable" && this.ECC_VARIABLE_TYPE == "Currency") {
    showCurrencyFormat = "YES";
} else {
    if (this.ECC_VALUE_TYPE == "Variable" && this.ECC_VARIABLE_TYPE == "Array") {
        for(var i = 0; i < tableVariables.length; i++) {
            if (tableVariables[i]["ECC_ARRAY_VARIABLE_TYPE"] == "Currency") {
               showCurrencyFormat = "YES";
               break;
            }
        }
    }
}
return showCurrencyFormat;

/****************************************************
 * Check if field Symbol position should be required
 * 
 * by Cinthia Romero
 ***************************************************/
var requireSymbolPosition = "NO";
if (this.ECC_CURRENCY_SYMBOL != "" && this.ECC_CURRENCY_SYMBOL != undefined && this.ECC_CURRENCY_SYMBOL != null) {
    requireSymbolPosition = "YES";
}

/***************************************************
 * Check if percentage format field should be shown
 * 
 * by Cinthia Romero
 **************************************************/
var tableVariables = this.ECC_TABLE_VARIABLES;
var showPercentageFormat = "NO";
if (this.ECC_VALUE_TYPE == "Variable" && this.ECC_VARIABLE_TYPE == "Percentage") {
    showPercentageFormat = "YES";
} else {
    if (this.ECC_VALUE_TYPE == "Variable" && this.ECC_VARIABLE_TYPE == "Array") {
        for(var i = 0; i < tableVariables.length; i++) {
            if (tableVariables[i]["ECC_ARRAY_VARIABLE_TYPE"] == "Percentage") {
               showPercentageFormat = "YES";
               break;
            }
        }
    }
}
return showPercentageFormat;
